    static int solve1(final String input) {
        int floor = 0;

        for (final char c : input.toCharArray()) {
            if (c == '(')
                floor++;
            else
                floor--;
        }

        return floor;
    }

    static int solve2(final String input) {
        int floor = 0;
        final char[] in = input.toCharArray();

        for (int i = 0; i < input.length(); i++) {
            if (in[i] == '(') {
                floor++;
            } else {
                floor--;
                if (floor == -1) {
                    return i + 1;
                }
            }
        }

        return -1;
    }
